<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Bouncing Ball Physics Playground</title>
    <style>
        body {
            background-color: #333;
            color: white;
            margin: 0;
            padding: 20px;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
        }

        #sim {
            width: 400px;
            height: 400px;
            background-color: #f9f9f9;
            border-radius: 10px;
            box-shadow: 0 4px 8px rgba(0,0,0,0.2);
            margin-bottom: 20px;
        }

        button {
            padding: 10px 15px;
            font-size: 14px;
            cursor: pointer;
        }

        #drop { background-color: #4CAF50; color: white; border: none; }
        #play { background-color: #2196F3; color: white; border: none; }
        #clear { background-color: #f44336; color: white; border: none; }
    </style>
</head>
<body>
    <div id="sim"></div>

    <script>
        const windowSim = {
            w: 400,
            h: 400,
            balls: [],
            addBall(x, y, vx=0, vy=0, r?), // add a ball
            clear(),
            step(dt=1)
        };

        function Ball(x, y, vx, vy, r) {
            this.x = x;
            this.y = y;
            this.vx = vx;
            this.vy = vy; // vertical velocity
            this.r = r;
        }

        windowSim.balls.push(new Ball(0, 200, 5, 2, 1));

        function addBall(x, y, vx=0, vy=0, r) {
            const newBall = new Ball(x, y, vx, vy, r);
            windowSim.balls.push(newBall);
        }

        function clear() {
            windowSim.balls = [];
        }

        function step(dt) {
            for (let i = 0; i < windowSim.balls.length; i++) {
                const ball = windowSim.balls[i];

                // Gravity: increase vy by a small amount each step
                ball.vy += 0.1;

                // Clamp x coordinate to canvas boundaries
                if (ball.x < 0) {
                    ball.x = 0;
                    ball.vx *= -1; // reverse vx when moving left edge
                } else if (ball.x > windowSim.w) {
                    ball.x = windowSim.w;
                    ball.vx *= -1; // reverse vx when moving right edge
                }

                // Clamp y coordinate to canvas boundaries
                if (ball.y < 0) {
                    ball.y = 0;
                    ball.vy *= -1; // reverse vy when moving bottom edge
                } else if (ball.y > windowSim.h) {
                    ball.y = windowSim.h;
                    ball.vy *= -1; // reverse vy when moving top edge
                }
            }
        }
    </script>
</body>
</html>
